const body = $input.first().json.body || $input.first().json;
const documentType = body.document_type;
const context = body.context || {};

// Embedded validation schemas
const schemas = {
  contractor_agreement: { required: ['contractor_name', 'effective_date', 'services_description'] },
  client_contract: { required: ['client_name', 'service_type', 'project_description', 'pricing'] },
  operating_agreement_update: { required: ['amendment_description', 'effective_date'] },
  emergency_ops_binder: { required: [] },
  data_retention_policy: { required: [] },
  nda: { required: ['party_name', 'party_address', 'effective_date'] },
  policy_update: { required: ['policy_name', 'policy_description'] }
};

if (!documentType || !schemas[documentType]) {
  throw new Error('Invalid document_type: ' + documentType + '. Valid types: ' + Object.keys(schemas).join(', '));
}

const schema = schemas[documentType];
const missing = schema.required.filter(f => !context[f]);
if (missing.length > 0) {
  throw new Error('Missing required fields for ' + documentType + ': ' + missing.join(', '));
}

// Reference path mapping
const referenceMap = {
  contractor_agreement: 'reference/section-7.5.2-contractor-management.md',
  client_contract: 'reference/section-3-service-pricing.md',
  operating_agreement_update: 'reference/section-7.5.1-operating-agreement.md',
  emergency_ops_binder: 'reference/section-7.5.5-emergency-ops.md',
  data_retention_policy: 'reference/section-4.7-data-retention.md',
  nda: 'reference/section-7.5-legal-governance.md',
  policy_update: 'reference/section-7.5-legal-governance.md'
};

const now = new Date();
const datestamp = now.toISOString().slice(0, 10);
const month = now.getMonth();
const quarter = 'Q' + (Math.floor(month / 3) + 1);
const fiscalYear = now.getFullYear();
const storagePath = 'drafts/' + datestamp + '_' + documentType + '.docx';

return [{
  json: {
    document_type: documentType,
    context,
    datestamp,
    storage_path: storagePath,
    reference_path: referenceMap[documentType],
    quarter,
    fiscal_year: fiscalYear
  }
}];

const prev = $('Validate Payload').first().json;
const refResponse = $input.first().json;
const referenceContent = (typeof refResponse === 'string') ? refResponse : (refResponse.data || refResponse.body || '');

const ctx = prev.context;
const docType = prev.document_type;

// Base system prompt
const basePrompt = `You are a legal document drafting assistant for Faith & Harmony LLC (DBA Sentinel Aerial Inspections), a single-member Virginia LLC providing commercial drone, aerial photography, and property inspection services. The sole member and managing member is Dradamo Pierce.

Your task is to generate a legal document draft as structured JSON.

Writing standards:
- Active voice throughout
- Direct, clear legal language
- No marketing fluff or corporate jargon
- Use numbered sections and subsections
- Keep sentences concise and unambiguous

[ATTORNEY REVIEW] placeholders:
- Insert [ATTORNEY REVIEW: brief description] in any section requiring professional legal judgment
- Do NOT include specific Virginia Code citations
- Every document MUST have at least one [ATTORNEY REVIEW] placeholder

Output format: Return ONLY valid JSON with this structure:
{
  "title": "Document title",
  "date_line": "Effective date or draft date",
  "sections": [
    {
      "heading": "Section title",
      "number": "1",
      "content": "Section content text",
      "subsections": [
        { "number": "1.1", "content": "Subsection content" }
      ]
    }
  ]
}

Business context:
` + (referenceContent || 'No reference data available.') + `

Respond with raw JSON only. No markdown code fences.`;

// Per-type prompts
const typePrompts = {
  contractor_agreement: `Generate an Independent Contractor Agreement with:
Contractor: ${ctx.contractor_name || 'TBD'}
Effective Date: ${ctx.effective_date || 'TBD'}
Services: ${ctx.services_description || 'TBD'}
Compensation: ${ctx.compensation_rate || 'TBD'} (${ctx.compensation_structure || 'per job'})
Term: ${ctx.term_months || '12'} months
Territory: ${ctx.territory || 'Virginia'}

Include 14 sections: Parties/Recitals, Scope of Services, Term/Termination, Compensation/Payment, Independent Contractor Status, Equipment/Materials, Insurance Requirements [ATTORNEY REVIEW], IP Assignment [ATTORNEY REVIEW], Confidentiality, Non-Compete/Non-Solicitation [ATTORNEY REVIEW], Indemnification [ATTORNEY REVIEW], Limitation of Liability [ATTORNEY REVIEW], General Provisions (Virginia governing law), Signature Block.

Virginia-specific: governed by Virginia law, reasonable non-compete scope, satisfy Virginia employment law tests.`,

  client_contract: `Generate a Client Service Agreement with:
Client: ${ctx.client_name || 'TBD'}
Company: ${ctx.client_company || ''}
Service Type: ${ctx.service_type || 'TBD'}
Project: ${ctx.project_description || 'TBD'}
Pricing: ${ctx.pricing || 'TBD'}
Completion: ${ctx.estimated_completion || 'TBD'}
Special Terms: ${ctx.special_terms || 'None'}

Include 13 sections: Parties, Scope of Services, Deliverables, Pricing/Payment [ATTORNEY REVIEW], Timeline, Client Responsibilities, Liability/Insurance [ATTORNEY REVIEW], Data Handling/Privacy [ATTORNEY REVIEW], Cancellation/Refund, Force Majeure, Governing Law (Virginia), General Provisions, Signature Block.

Pricing reference: Residential $400+, Commercial $750+, Retainer $1,500/mo.`,

  operating_agreement_update: `Generate an Operating Agreement Amendment for Faith & Harmony LLC with the following details:
Amendment Description: ${ctx.amendment_description || 'TBD'}
Effective Date: ${ctx.effective_date || 'TBD'}
Resolution Reference: ${ctx.resolution_reference || ''}
Rationale: ${ctx.rationale || ''}

The amendment must include all of the following sections:

1. Recitals - State that Faith & Harmony LLC is a Virginia single-member LLC, identify the original Operating Agreement date, and state the purpose of this amendment.

2. Amendment Details - Describe the specific changes to the Operating Agreement. Reference the exact sections being modified. Use clear 'is hereby amended to read as follows' language.

3. Rationale - Explain the business justification for the amendment. Reference any governance decision or resolution that authorized this change.

4. Effect on Remaining Provisions - State that all other provisions of the Operating Agreement remain in full force and effect. [ATTORNEY REVIEW: confirm no conflicts with existing provisions]

5. Severability - If any provision of this amendment is held invalid, the remaining provisions continue in effect.

6. Effective Date - Specify when the amendment takes effect.

7. Certification - Statement that the sole member has duly authorized and executed this amendment.

8. Signature Block - Space for sole member signature with printed name, title (Managing Member), and date.

Virginia-specific: Reference Virginia Limited Liability Company Act as governing law. [ATTORNEY REVIEW: verify compliance with Virginia LLC Act requirements for operating agreement amendments]`,

  emergency_ops_binder: `Generate an Emergency Operations Binder for Faith & Harmony LLC (DBA Sentinel Aerial Inspections) drone operations.
Focus Area: ${ctx.focus_area || ''}
Additional Contacts: ${ctx.additional_contacts || ''}

The binder must include all of the following sections:

1. Emergency Contact List - Include FAA emergency line, local emergency services (911), insurance provider, legal counsel contact placeholder, equipment manufacturer support lines, and company emergency contacts.

2. Incident Response Procedures - Step-by-step procedures for drone crashes, property damage incidents, personal injury incidents, and near-miss events. Include immediate actions, documentation requirements, and notification chain.

3. Equipment Failure Protocols - Procedures for in-flight equipment failures, battery emergencies, GPS loss, communication link failure, and camera/sensor malfunctions. Include safe landing procedures and equipment quarantine steps.

4. Weather Emergency Procedures - Decision criteria for weather-related flight cancellation or delay. Include wind speed limits, precipitation thresholds, visibility minimums, and lightning/storm protocols. Reference FAA Part 107 weather requirements.

5. Client Communication Templates - Pre-written templates for: incident notification to client, weather delay notification, rescheduling communication, and post-incident follow-up.

6. Insurance Claims Process - Step-by-step guide for filing insurance claims after incidents. Include documentation checklist, photo/video evidence requirements, timeline for filing, and contact information for the insurance claims adjuster.

7. FAA Incident Reporting Requirements - Summary of when and how to report incidents to the FAA. Include the accident and incident reporting thresholds, reporting timelines, and form references. [ATTORNEY REVIEW: verify current FAA reporting requirements and thresholds]

8. Evidence Preservation Protocol - Procedures for preserving drone flight logs, telemetry data, video footage, and witness statements after any incident. Include chain of custody requirements.

9. Recovery and Return to Operations - Procedures for equipment inspection after incidents, return-to-service requirements, post-incident review meetings, and lessons learned documentation.`,

  data_retention_policy: `Generate a Data Retention Policy for Faith & Harmony LLC (DBA Sentinel Aerial Inspections).
Retention Period Override: ${ctx.retention_period_override || ''}
Specific Data Types: ${ctx.specific_data_types || ''}

The policy must include all of the following sections:

1. Purpose - State the purpose of the data retention policy and its applicability to all company data.

2. Scope - Define which data this policy covers: drone inspection imagery, aerial photographs, video footage, client information, financial records, personnel files, contracts, and operational data.

3. Data Categories and Retention Periods:
   - Drone imagery and inspection reports: 7 years (client deliverables)
   - Raw flight data and telemetry: 3 years
   - Client contact and project information: Duration of relationship plus 5 years
   - Financial records and tax documents: 7 years per IRS requirements
   - Employee/contractor records: Duration of engagement plus 4 years
   - Contracts and legal documents: Duration of agreement plus 7 years
   - Marketing materials and proposals: 3 years
   - Internal communications: 2 years
   [ATTORNEY REVIEW: verify retention periods comply with Virginia and federal requirements]

4. Storage and Security - Describe storage locations (Supabase cloud, local backups), encryption requirements, access controls, and backup procedures.

5. Access Controls - Define who can access which data categories. Specify authentication requirements and audit logging.

6. Data Disposal Procedures - Describe secure deletion methods for digital data. Include certificate of destruction requirements for sensitive data.

7. Client Data Rights - Address client requests for data access, data portability, and data deletion. Include response timeframes. [ATTORNEY REVIEW: Virginia Consumer Data Protection Act compliance requirements]

8. Compliance Requirements - Reference applicable regulations: Virginia Consumer Data Protection Act, FAA recordkeeping requirements, IRS document retention rules.

9. Incident Response for Data Breaches - Procedures for identifying, containing, and reporting data breaches. Include notification timelines and requirements. [ATTORNEY REVIEW: Virginia data breach notification requirements]

10. Policy Review Schedule - This policy will be reviewed annually or when significant changes occur in operations or applicable laws.`,

  nda: `Generate a Mutual Non-Disclosure Agreement between Faith & Harmony LLC and the following party:
Party Name: ${ctx.party_name || 'TBD'}
Party Address: ${ctx.party_address || 'TBD'}
Effective Date: ${ctx.effective_date || 'TBD'}
Scope Description: ${ctx.scope_description || ctx.purpose || ''}
Term: ${ctx.term_months || ctx.term_years ? (ctx.term_years * 12) : '24'} months

The NDA must include all of the following sections:

1. Parties - Identify Faith & Harmony LLC (DBA Sentinel Aerial Inspections) as the first party and the named party as the second party. Include addresses.

2. Purpose - State the purpose of the mutual exchange of confidential information (business relationship evaluation, contractor engagement, partnership discussion, etc.).

3. Definition of Confidential Information - Define what constitutes confidential information for both parties. Include: business plans, financial information, client lists, pricing strategies, proprietary inspection methodologies, drone operation procedures, technical specifications, and trade secrets.

4. Exclusions from Confidential Information - Standard exclusions: publicly available information, independently developed information, information received from third parties without restriction, and information required by law to disclose.

5. Obligations of Receiving Party - Non-disclosure, non-use except for stated purpose, protection standards (at least same as own confidential information), and limitation of access to authorized personnel.

6. Term of Agreement - Specify the agreement duration and state that confidentiality obligations survive termination for a period of 2 years (or as specified). [ATTORNEY REVIEW: appropriate survival period for drone services industry]

7. Return of Materials - Upon termination or request, all confidential materials must be returned or destroyed with written certification.

8. Remedies - Acknowledge that breach may cause irreparable harm and that injunctive relief may be sought in addition to other remedies. [ATTORNEY REVIEW: specific remedies and injunctive relief provisions under Virginia law]

9. Governing Law and Jurisdiction - This agreement is governed by the laws of the Commonwealth of Virginia. Specify venue for disputes.

10. General Provisions - Entire agreement, amendment requirement (written and signed), severability, waiver, assignment restrictions, and counterparts.

11. Signature Block - Spaces for both parties to sign with printed name, title, date.`,

  policy_update: `Generate an Internal Policy Document for Faith & Harmony LLC (DBA Sentinel Aerial Inspections):
Policy Name: ${ctx.policy_name || 'TBD'}
Policy Description: ${ctx.policy_description || 'TBD'}
Effective Date: ${ctx.effective_date || ''}
Supersedes: ${ctx.supersedes || 'N/A'}

The policy document must include all of the following sections:

1. Purpose - State the purpose and objectives of this policy clearly and concisely.

2. Scope - Define who this policy applies to (employees, contractors, vendors) and under what circumstances.

3. Definitions - Define key terms used throughout the policy to avoid ambiguity.

4. Policy Statement - The core policy content. State the rules, standards, and expectations clearly. Use numbered or lettered items for multiple provisions.

5. Procedures - Step-by-step procedures for implementing and following the policy. Include workflow descriptions where applicable.

6. Roles and Responsibilities - Define who is responsible for policy implementation, oversight, enforcement, and exception approval.

7. Compliance and Enforcement - Describe consequences for non-compliance and the process for reporting violations. [ATTORNEY REVIEW: enforcement and disciplinary provisions, regulatory compliance claims, liability waivers in safety policies]

8. Exceptions - Process for requesting and approving exceptions to the policy. Specify approval authority.

9. Related Documents - Reference any related policies, procedures, or external regulations.

10. Version History - Include a version history table with date, version number, and description of changes.

11. Review and Updates - State the review frequency (annual recommended) and the process for proposing amendments.

12. Acknowledgment - Statement that all covered individuals must acknowledge receipt and understanding of this policy.

If this policy supersedes a previous version, include a summary of key changes from the prior version.`
};

const userPrompt = typePrompts[docType] || 'Generate a document based on the provided context.';

return [{
  json: {
    system_prompt: basePrompt,
    user_prompt: userPrompt,
    document_type: docType,
    context: ctx,
    datestamp: prev.datestamp,
    storage_path: prev.storage_path,
    quarter: prev.quarter,
    fiscal_year: prev.fiscal_year
  }
}];

const response = $json;
const prev = $('Build Prompts').first().json;

let text = response.content[0].text.trim();
// Strip markdown code fences
if (text.startsWith('```')) {
  text = text.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}

let doc;
try {
  doc = JSON.parse(text);
} catch (e) {
  throw new Error('Failed to parse Claude response: ' + e.message + '. First 200 chars: ' + text.substring(0, 200));
}

if (!doc.title || !doc.sections || !Array.isArray(doc.sections)) {
  throw new Error('Invalid document structure: missing title or sections array');
}

return [{
  json: {
    document: doc,
    document_type: prev.document_type,
    context: prev.context,
    datestamp: prev.datestamp,
    storage_path: prev.storage_path,
    quarter: prev.quarter,
    fiscal_year: prev.fiscal_year
  }
}];

const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, Header, Footer } = require('docx');

const doc = $json.document;
const children = [];

// Helper: process text with [ATTORNEY REVIEW] highlighting
function processText(text) {
  if (!text) return [new TextRun({ text: '' })];
  const parts = String(text).split(/(\[ATTORNEY REVIEW:[^\]]*\])/);
  return parts.map(part => {
    if (part.match(/^\[ATTORNEY REVIEW:/)) {
      return new TextRun({ text: part, bold: true, color: 'FF0000', highlight: 'yellow' });
    }
    return new TextRun({ text: part });
  });
}

// Title
children.push(new Paragraph({
  children: [new TextRun({ text: doc.title, bold: true, size: 32 })],
  alignment: AlignmentType.CENTER
}));
children.push(new Paragraph({
  text: doc.date_line || $json.datestamp,
  alignment: AlignmentType.CENTER
}));
children.push(new Paragraph({ text: '' }));

// Sections
for (const section of doc.sections) {
  children.push(new Paragraph({
    text: (section.number ? section.number + '. ' : '') + section.heading,
    heading: HeadingLevel.HEADING_1
  }));

  if (section.content) {
    const contentParts = section.content.split('\n\n');
    for (const part of contentParts) {
      if (part.trim()) {
        children.push(new Paragraph({ children: processText(part.trim()) }));
      }
    }
  }

  if (section.subsections) {
    for (const sub of section.subsections) {
      children.push(new Paragraph({
        children: [
          new TextRun({ text: sub.number + ' ', bold: true }),
          ...processText(sub.content || '')
        ],
        indent: { left: 360 }
      }));
    }
  }

  children.push(new Paragraph({ text: '' }));
}

const document = new Document({
  sections: [{
    headers: {
      default: new Header({
        children: [new Paragraph({
          children: [new TextRun({ text: 'Faith & Harmony LLC - DRAFT - ATTORNEY REVIEW REQUIRED', italics: true, size: 16, color: '999999' })],
          alignment: AlignmentType.CENTER
        })]
      })
    },
    footers: {
      default: new Footer({
        children: [new Paragraph({
          children: [new TextRun({ text: 'CONFIDENTIAL DRAFT - NOT FOR EXECUTION', italics: true, size: 16, color: '999999' })],
          alignment: AlignmentType.CENTER
        })]
      })
    },
    children
  }]
});

const buffer = await Packer.toBuffer(document);
const filename = $json.datestamp + '_' + $json.document_type + '.docx';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(buffer),
  filename,
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
);

return [{
  json: {
    filename,
    storage_path: $json.storage_path,
    document_type: $json.document_type,
    context: $json.context,
    datestamp: $json.datestamp,
    quarter: $json.quarter,
    fiscal_year: $json.fiscal_year,
    document_title: doc.title
  },
  binary: { data: binaryData }
}];
